interface.definition:
#"SYSTEM_SYSRULES_sectionLayout_v1"(
  label: "Weather Channel",
  labelSize: "LARGE",
  contents: {
    #"SYSTEM_SYSRULES_richTextDisplayField"(
      labelPosition: "COLLAPSED",
      value: {
        #"SYSTEM_SYSRULES_richTextItem_v1"(
          text: "Welcome to the Weather Channel modernization application.",
          color: "SECONDARY"
        )
      }
    ),
    #"SYSTEM_SYSRULES_cardLayout"(
      contents: {
        #"SYSTEM_SYSRULES_richTextDisplayField"(
          labelPosition: "COLLAPSED",
          value: {
            #"SYSTEM_SYSRULES_richTextItem_v1"(text: "Data model (5 entities):",
                           size: "MEDIUM", style: "STRONG")
          }
        )
      },
      padding: "STANDARD",
      marginBelow: "STANDARD",
      showBorder: false
    ),
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            labelPosition: "COLLAPSED",
            value: {
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "WeatherQuery", size: "MEDIUM_PLUS", style: "STRONG"),
              char(10),
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "Captures user requests for weather information including the city and preferred temperature scale.", color: "SECONDARY")
            }
          )
        },
        style: "STANDARD",
        padding: "STANDARD",
        marginBelow: "STANDARD",
        showBorder: true,
        showShadow: true
      ),
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            labelPosition: "COLLAPSED",
            value: {
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "WeatherForecast", size: "MEDIUM_PLUS", style: "STRONG"),
              char(10),
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "Stores the detailed weather forecast data retrieved from the external weather API for a specific city and time.", color: "SECONDARY")
            }
          )
        },
        style: "STANDARD",
        padding: "STANDARD",
        marginBelow: "STANDARD",
        showBorder: true,
        showShadow: true
      ),
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            labelPosition: "COLLAPSED",
            value: {
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "City", size: "MEDIUM_PLUS", style: "STRONG"),
              char(10),
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "Maintains a catalog of cities with their geographic coordinates for efficient weather lookups and data caching.", color: "SECONDARY")
            }
          )
        },
        style: "STANDARD",
        padding: "STANDARD",
        marginBelow: "STANDARD",
        showBorder: true,
        showShadow: true
      ),
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            labelPosition: "COLLAPSED",
            value: {
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "ApiConfiguration", size: "MEDIUM_PLUS", style: "STRONG"),
              char(10),
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "Stores configuration settings for external weather API integration including credentials and endpoints.", color: "SECONDARY")
            }
          )
        },
        style: "STANDARD",
        padding: "STANDARD",
        marginBelow: "STANDARD",
        showBorder: true,
        showShadow: true
      ),
      #"SYSTEM_SYSRULES_cardLayout"(
        contents: {
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            labelPosition: "COLLAPSED",
            value: {
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "UserPreference", size: "MEDIUM_PLUS", style: "STRONG"),
              char(10),
              #"SYSTEM_SYSRULES_richTextItem_v1"(text: "Tracks individual user preferences for weather display including default temperature scale and favorite cities.", color: "SECONDARY")
            }
          )
        },
        style: "STANDARD",
        padding: "STANDARD",
        marginBelow: "STANDARD",
        showBorder: true,
        showShadow: true
      )
  }
)
